I am working on a React application. Here is the current code for App.jsx: import React, { useState, useEffect, useRef } from 'react';
import { 
  Music, 
  Upload, 
  Play, 
  Check, 
  ChevronRight, 
  ChevronLeft, 
  Download, 
  RefreshCw, 
  Layers, 
  Instagram, 
  Disc, 
  Video, 
  Zap, 
  Sparkles,
  X
} from 'lucide-react';

/**
 * MOCK DATA & CONFIGURATION
 */
const GENRES = ["Trap", "House", "Bedroom Pop", "Ambient", "Drum & Bass", "Indie Rock", "Techno"];
const MOODS = ["Dark", "Dreamy", "Energetic", "Melancholic", "Euphoric", "Gritty", "Chill"];

const VISUAL_STYLES = [
  {
    id: 'neon-cybertrap',
    title: 'Neon Cybertrap',
    desc: 'High-contrast neon glitches with dark geometric underlays.',
    color1: '#ff00cc',
    color2: '#333399'
  },
  {
    id: 'retro-vhs',
    title: 'Retro VHS',
    desc: 'Analog noise, scanlines, and washed-out warm nostalgia.',
    color1: '#ff9966',
    color2: '#ff5e62'
  },
  {
    id: 'pastel-dream',
    title: 'Pastel Dream',
    desc: 'Soft, floating gradients and ethereal light leaks.',
    color1: '#a18cd1',
    color2: '#fbc2eb'
  },
  {
    id: 'glitch-noir',
    title: 'Glitch Noir',
    desc: 'Monochrome static, sharp digital distortion, and minimalism.',
    color1: '#000000',
    color2: '#434343'
  },
  {
    id: 'celestial-ambient',
    title: 'Celestial Ambient',
    desc: 'Slow-moving starfields and deep cosmic nebulas.',
    color1: '#0f2027',
    color2: '#2c5364'
  }
];

const LOADING_MESSAGES = [
  "Analyzing BPM and key...",
  "Scoring your visuals...",
  "Rendering abstract waves...",
  "Mastering your Canvas loop...",
  "Compressing for social media...",
  "Polishing pixels..."
];

/**
 * UTILITY COMPONENTS
 */

// Simulated "Video" Component using CSS Animations
const AbstractLoop = ({ styleId, className }) => {
  const getGradient = () => {
    switch (styleId) {
      case 'neon-cybertrap': return 'bg-gradient-to-br from-pink-600 via-purple-900 to-blue-900';
      case 'retro-vhs': return 'bg-gradient-to-tr from-orange-400 via-red-500 to-pink-500';
      case 'pastel-dream': return 'bg-gradient-to-bl from-pink-200 via-purple-200 to-indigo-200';
      case 'glitch-noir': return 'bg-gradient-to-b from-gray-900 via-gray-800 to-black';
      case 'celestial-ambient': return 'bg-gradient-to-t from-slate-900 via-purple-900 to-slate-900';
      default: return 'bg-gradient-to-r from-blue-500 to-purple-600';
    }
  };

  return (
    <div className={`relative overflow-hidden w-full h-full ${getGradient()} ${className}`}>
      {/* Animated blob 1 */}
      <div className="absolute top-0 left-0 w-full h-full opacity-40 animate-pulse mix-blend-overlay">
        <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] bg-gradient-to-r from-transparent via-white to-transparent rotate-45 animate-shimmer" />
      </div>
       {/* Animated blob 2 */}
      <div className="absolute bottom-[-20%] right-[-20%] w-[80%] h-[80%] bg-white blur-3xl opacity-10 animate-blob" />

      {/* Style specific overlays */}
      {styleId === 'retro-vhs' && (
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none"></div>
      )}
       {styleId === 'glitch-noir' && (
        <div className="absolute inset-0 bg-[repeating-linear-gradient(0deg,transparent,transparent_2px,#000_3px)] opacity-20 pointer-events-none"></div>
      )}
    </div>
  );
};

// New Visual Showcase Component for Hero
const HeroVisuals = () => {
  return (
    <div className="relative w-full max-w-5xl mx-auto mt-16 lg:mt-24 h-[350px] md:h-[500px] perspective-[1000px] pointer-events-none select-none px-4">
       {/* Background Glow */}
       <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300px] md:w-[600px] h-[300px] md:h-[600px] bg-cyan-500/20 rounded-full blur-[80px] md:blur-[120px] -z-10 mix-blend-screen animate-pulse-slow"></div>

       {/* Center - Spotify Canvas (Phone-like) */}
       <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[180px] md:w-[260px] aspect-[9/16] z-20 animate-float-slow">
          <div className="w-full h-full rounded-[2rem] border-[6px] border-gray-900 bg-gray-950 shadow-2xl shadow-cyan-500/30 overflow-hidden relative">
             <AbstractLoop styleId="neon-cybertrap" />

             {/* UI Overlays */}
             <div className="absolute top-0 inset-x-0 h-24 bg-gradient-to-b from-black/80 to-transparent p-4 flex justify-between items-start">
                <div className="flex gap-1">
                   <div className="w-8 h-1 bg-white/40 rounded-full"></div>
                   <div className="w-8 h-1 bg-white/40 rounded-full"></div>
                </div>
                <div className="text-[8px] md:text-[10px] font-bold text-white/50 uppercase tracking-widest">Canvas</div>
             </div>

             <div className="absolute bottom-0 inset-x-0 h-32 bg-gradient-to-t from-black/90 via-black/50 to-transparent p-5 flex flex-col justify-end">
                <div className="flex items-center gap-3">
                   <div className="w-8 h-8 md:w-10 md:h-10 rounded-lg bg-white/10 backdrop-blur-sm flex items-center justify-center border border-white/10">
                      <Music size={16} className="text-white" />
                   </div>
                   <div>
                      <div className="h-1.5 md:h-2 w-16 md:w-20 bg-white/80 rounded-full mb-1.5"></div>
                      <div className="h-1.5 md:h-2 w-10 md:w-12 bg-white/40 rounded-full"></div>
                   </div>
                </div>
             </div>
          </div>
       </div>

       {/* Left - Cover Art */}
       <div className="absolute top-20 md:top-16 left-[2%] md:left-[15%] w-[140px] md:w-[220px] aspect-square z-10 animate-float-delayed">
          <div className="w-full h-full rounded-xl border border-white/10 bg-gray-900 shadow-2xl -rotate-6 overflow-hidden relative group transition-transform duration-500">
             <AbstractLoop styleId="pastel-dream" />
             <div className="absolute inset-0 bg-black/10 flex items-center justify-center">
                 <h2 className="text-xl md:text-2xl font-black text-white mix-blend-overlay tracking-tighter opacity-80">SINGLE</h2>
             </div>
             <div className="absolute bottom-3 left-3 bg-black/60 backdrop-blur-md px-2 py-1 rounded text-[8px] md:text-[10px] border border-white/10 text-white/80 uppercase tracking-wider">
                Cover Art
             </div>
          </div>
       </div>

       {/* Right - Social Clip */}
       <div className="absolute top-12 md:top-10 right-[2%] md:right-[15%] w-[130px] md:w-[200px] aspect-[9/16] z-10 animate-float">
          <div className="w-full h-full rounded-2xl border border-white/10 bg-gray-900 shadow-2xl rotate-6 overflow-hidden relative transition-transform duration-500">
             <AbstractLoop styleId="retro-vhs" />
             {/* Social UI */}
             <div className="absolute right-2 bottom-12 md:bottom-16 flex flex-col gap-2">
                <div className="w-6 h-6 md:w-8 md:h-8 rounded-full bg-black/40 backdrop-blur-md border border-white/10 flex items-center justify-center">
                   <div className="text-[10px] text-white/80">♥</div>
                </div>
                <div className="w-6 h-6 md:w-8 md:h-8 rounded-full bg-black/40 backdrop-blur-md border border-white/10"></div>
             </div>
              <div className="absolute bottom-3 left-3 bg-black/60 backdrop-blur-md px-2 py-1 rounded text-[8px] md:text-[10px] border border-white/10 text-white/80 uppercase tracking-wider">
                Story
             </div>
          </div>
       </div>
    </div>
  );
};

const GlassCard = ({ children, className = "", hoverEffect = false, onClick = null }) => (
  <div 
    onClick={onClick}
    className={`
      backdrop-blur-xl bg-white/5 border border-white/10 shadow-2xl rounded-2xl 
      transition-all duration-300 ease-out
      ${hoverEffect ? 'hover:bg-white/10 hover:border-white/20 hover:scale-[1.01] cursor-pointer' : ''}
      ${className}
    `}
  >
    {children}
  </div>
);

const Button = ({ children, variant = "primary", className = "", onClick, disabled }) => {
  const baseStyle = "px-6 py-3 rounded-xl font-semibold transition-all duration-200 flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed";
  const variants = {
    primary: "bg-gradient-to-r from-cyan-500 to-violet-600 text-white shadow-lg hover:shadow-cyan-500/25 hover:brightness-110",
    secondary: "bg-white/10 text-white hover:bg-white/20 border border-white/10",
    ghost: "text-white/70 hover:text-white hover:bg-white/5"
  };

  return (
    <button onClick={onClick} disabled={disabled} className={`${baseStyle} ${variants[variant]} ${className}`}>
      {children}
    </button>
  );
};

const ProgressBar = ({ step, totalSteps }) => {
  const progress = ((step - 1) / (totalSteps - 1)) * 100;
  return (
    <div className="w-full max-w-md mx-auto mb-8">
      <div className="flex justify-between mb-2 text-xs font-medium text-white/50 uppercase tracking-wider">
        <span>Details</span>
        <span>Style</span>
        <span>Outputs</span>
        <span>Review</span>
      </div>
      <div className="h-2 bg-white/10 rounded-full overflow-hidden">
        <div 
          className="h-full bg-gradient-to-r from-cyan-400 to-violet-500 transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        />
      </div>
    </div>
  );
};

/**
 * MAIN APP COMPONENT
 */
export default function ReleaseVisualPackApp() {
  const [view, setView] = useState('hero'); // 'hero', 'wizard', 'results'
  const [showDemo, setShowDemo] = useState(false);

  // Wizard State
  const [step, setStep] = useState(1);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [loadingText, setLoadingText] = useState(LOADING_MESSAGES[0]);

  // Form Data
  const [formData, setFormData] = useState({
    trackFile: null,
    trackName: '',
    artistName: '',
    genre: '',
    mood: '',
    style: null,
    outputs: {
      coverArt: true,
      spotifyCanvas: true,
      socialClips: true
    }
  });

  const handleStart = () => setView('wizard');

  const handleNext = () => {
    if (step < 4) setStep(step + 1);
    else handleGenerate();
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
    else setView('hero');
  };

  const handleGenerate = () => {
    setIsGenerating(true);
    let progress = 0;

    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 5) + 2;
      if (progress > 100) progress = 100;

      setLoadingProgress(progress);

      // Update loading text periodically
      if (progress % 20 === 0 && progress < 100) {
        setLoadingText(LOADING_MESSAGES[Math.floor(Math.random() * LOADING_MESSAGES.length)]);
      }

      if (progress === 100) {
        clearInterval(interval);
        setTimeout(() => {
          setIsGenerating(false);
          setView('results');
        }, 800);
      }
    }, 150);
  };

  const resetApp = () => {
    setStep(1);
    setLoadingProgress(0);
    setFormData({
      trackFile: null,
      trackName: '',
      artistName: '',
      genre: '',
      mood: '',
      style: null,
      outputs: { coverArt: true, spotifyCanvas: true, socialClips: true }
    });
    setView('wizard');
  };

  // Background Styles
  const bgStyle = {
    background: `
      radial-gradient(circle at 15% 50%, rgba(76, 29, 149, 0.4), transparent 25%),
      radial-gradient(circle at 85% 30%, rgba(219, 39, 119, 0.2), transparent 25%),
      linear-gradient(to bottom right, #0f172a, #1e1b4b, #312e81)
    `
  };

  return (
    <div className="min-h-screen text-white font-sans selection:bg-cyan-500/30 selection:text-cyan-100 overflow-x-hidden" style={bgStyle}>
      {/* Noise Texture Overlay */}
      <div className="fixed inset-0 opacity-[0.03] pointer-events-none z-0" style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}></div>

      {/* Main Content */}
      <div className="relative z-10 w-full min-h-screen flex flex-col">

        {/* Navigation / Header */}
        <nav className="w-full p-6 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('hero')}>
            <span className="font-bold text-lg tracking-tight">RVP: Release Visual Packs</span>
          </div>
          {view === 'results' && (
            <Button variant="secondary" className="!py-2 !px-4 text-sm" onClick={resetApp}>
              New Release
            </Button>
          )}
        </nav>

        {/* View Switcher */}
        <main className="flex-1 flex flex-col">
          {view === 'hero' && <HeroSection onStart={handleStart} onShowDemo={() => setShowDemo(true)} />}

          {view === 'wizard' && !isGenerating && (
            <Wizard 
              step={step} 
              formData={formData} 
              setFormData={setFormData} 
              onNext={handleNext} 
              onBack={handleBack} 
            />
          )}

          {isGenerating && (
            <div className="flex-1 flex items-center justify-center p-6 animate-fade-in">
              <LoadingScreen progress={loadingProgress} text={loadingText} />
            </div>
          )}

          {view === 'results' && (
            <ResultsView formData={formData} onReset={resetApp} />
          )}
        </main>

        {/* Footer */}
        <footer className="w-full p-6 text-center text-white/30 text-xs">
          <p>© 2025 RVP a NagaxMusic App | NagaVision LTD</p>
        </footer>
      </div>

      {/* Demo Modal */}
      {showDemo && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/80 backdrop-blur-sm animate-fade-in">
          <GlassCard className="w-full max-w-2xl p-1 relative overflow-hidden">
             <button onClick={() => setShowDemo(false)} className="absolute top-4 right-4 z-10 p-2 bg-black/50 hover:bg-black/70 rounded-full text-white transition-colors">
               <X size={20} />
             </button>
             <div className="relative aspect-video rounded-xl overflow-hidden bg-black">
                <AbstractLoop styleId="neon-cybertrap" />
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                  <h3 className="text-4xl font-bold tracking-tighter opacity-80 mix-blend-overlay">DEMO VISUAL</h3>
                </div>
             </div>
             <div className="p-6">
               <h3 className="text-xl font-bold mb-2">AI-Driven Visuals</h3>
               <p className="text-white/60">Our engine analyzes your track's stems, BPM, and mood to generate perfectly synced visual loops for Spotify Canvas and social media.</p>
             </div>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

/**
 * SUB-COMPONENTS
 */

const HeroSection = ({ onStart, onShowDemo }) => (
  <div className="flex-1 flex flex-col items-center justify-center text-center p-6 animate-fade-in-up overflow-hidden">
    <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/5 border border-white/10 text-xs font-medium text-cyan-300 mb-6 backdrop-blur-md">
      <span className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse"></span>
      New Generation Engine V2
    </div>

    <h1 className="text-5xl md:text-7xl font-bold tracking-tight mb-6 max-w-4xl leading-tight">
      Visuals for your next release, <br />
      <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 via-violet-400 to-fuchsia-400">
        in minutes.
      </span>
    </h1>

    <p className="text-lg md:text-xl text-white/60 max-w-2xl mb-10 leading-relaxed">
      Upload your track, get cover art, Spotify Canvas loops, and social clips instantly. 
      No editing skills required.
    </p>

    <div className="flex flex-col sm:flex-row gap-4 w-full max-w-md mx-auto mb-8 relative z-30">
      <Button onClick={onStart} className="w-full text-lg py-4">
        Start a Release <ChevronRight size={20} />
      </Button>
      <Button variant="secondary" onClick={onShowDemo} className="w-full text-lg py-4">
        <Play size={20} /> Watch Demo
      </Button>
    </div>

    {/* Hero Visuals Showcase */}
    <HeroVisuals />

  </div>
);

const Wizard = ({ step, formData, setFormData, onNext, onBack }) => {
  const isStepValid = () => {
    if (step === 1) return formData.trackName && formData.artistName && formData.genre && formData.mood;
    if (step === 2) return formData.style;
    return true;
  };

  return (
    <div className="w-full max-w-5xl mx-auto p-4 md:p-6 flex flex-col flex-1 animate-fade-in">
      <ProgressBar step={step} totalSteps={4} />

      <GlassCard className="flex-1 flex flex-col p-6 md:p-10 min-h-[500px]">

        <div className="flex-1 mb-8">
          {step === 1 && <Step1Details formData={formData} setFormData={setFormData} />}
          {step === 2 && <Step2Style formData={formData} setFormData={setFormData} />}
          {step === 3 && <Step3Outputs formData={formData} setFormData={setFormData} />}
          {step === 4 && <Step4Review formData={formData} />}
        </div>

        <div className="flex items-center justify-between pt-6 border-t border-white/10">
          <Button variant="ghost" onClick={onBack} disabled={step === 1}>
            <ChevronLeft size={18} /> Back
          </Button>

          <Button onClick={onNext} disabled={!isStepValid()}>
            {step === 4 ? (
              <>Generate Pack <Zap size={18} fill="currentColor" /></>
            ) : (
              <>Next Step <ChevronRight size={18} /></>
            )}
          </Button>
        </div>

      </GlassCard>
    </div>
  );
};

const Step1Details = ({ formData, setFormData }) => {
  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setFormData({ ...formData, trackFile: { name: file.name, size: (file.size / 1024 / 1024).toFixed(2) + ' MB' } });
    }
  };

  return (
    <div className="grid md:grid-cols-2 gap-12 h-full">
      <div className="space-y-6">
        <div>
          <h2 className="text-3xl font-bold mb-2">Track Details</h2>
          <p className="text-white/50">Let's start with the basics of your new single.</p>
        </div>

        <div className="space-y-4">
          <div className="space-y-2">
            <label className="text-sm font-medium text-white/70">Audio File</label>
            <div className="relative border-2 border-dashed border-white/20 rounded-xl p-6 transition-colors hover:bg-white/5 hover:border-cyan-500/50 cursor-pointer group">
              <input type="file" accept="audio/*" onChange={handleFileChange} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
              <div className="flex flex-col items-center justify-center text-center">
                {formData.trackFile ? (
                   <>
                    <Music className="w-10 h-10 text-cyan-400 mb-2" />
                    <span className="font-medium text-white">{formData.trackFile.name}</span>
                    <span className="text-xs text-white/50">{formData.trackFile.size}</span>
                   </>
                ) : (
                   <>
                    <Upload className="w-10 h-10 text-white/30 mb-2 group-hover:text-cyan-400 transition-colors" />
                    <span className="font-medium text-white/80">Drop your track here</span>
                    <span className="text-xs text-white/40">MP3, WAV, AIFF up to 50MB</span>
                   </>
                )}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-sm font-medium text-white/70">Track Name</label>
              <input 
                type="text" 
                value={formData.trackName}
                onChange={(e) => setFormData({...formData, trackName: e.target.value})}
                placeholder="e.g. Midnight City"
                className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-3 text-white placeholder-white/20 focus:outline-none focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/50 transition-all"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-white/70">Artist Name</label>
              <input 
                type="text" 
                value={formData.artistName}
                onChange={(e) => setFormData({...formData, artistName: e.target.value})}
                placeholder="e.g. M83"
                className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-3 text-white placeholder-white/20 focus:outline-none focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/50 transition-all"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-white/70">Genre</label>
            <div className="flex flex-wrap gap-2">
              {GENRES.map(g => (
                <button
                  key={g}
                  onClick={() => setFormData({...formData, genre: g})}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.genre === g ? 'bg-cyan-500/20 border-cyan-500 text-cyan-200' : 'bg-white/5 border-white/10 text-white/60 hover:bg-white/10'}`}
                >
                  {g}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-white/70">Mood</label>
            <div className="flex flex-wrap gap-2">
              {MOODS.map(m => (
                <button
                  key={m}
                  onClick={() => setFormData({...formData, mood: m})}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${formData.mood === m ? 'bg-violet-500/20 border-violet-500 text-violet-200' : 'bg-white/5 border-white/10 text-white/60 hover:bg-white/10'}`}
                >
                  {m}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Dynamic Preview Card */}
      <div className="hidden md:flex items-center justify-center p-8 bg-black/20 rounded-2xl border border-white/5">
        <div className="w-64 aspect-square bg-gradient-to-br from-gray-800 to-black rounded-lg shadow-2xl flex flex-col items-center justify-center p-6 relative overflow-hidden">
            {/* Fake Waveform */}
            <div className="absolute inset-x-0 bottom-0 h-24 flex items-end justify-center gap-1 opacity-30 pb-4 px-4">
                {[...Array(20)].map((_, i) => (
                    <div key={i} className="w-1 bg-white rounded-t-sm" style={{ height: `${Math.random() * 80 + 20}%`}}></div>
                ))}
            </div>

            <div className="z-10 text-center">
                <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-4 mx-auto backdrop-blur-md">
                    <Music size={24} className="text-white/80" />
                </div>
                <h3 className="font-bold text-lg leading-tight mb-1">{formData.trackName || "Track Name"}</h3>
                <p className="text-sm text-white/50">{formData.artistName || "Artist Name"}</p>
            </div>
        </div>
      </div>
    </div>
  );
};

const Step2Style = ({ formData, setFormData }) => {
  return (
    <div className="h-full flex flex-col">
      <div className="mb-6">
