import React from 'react';
import { ChevronLeft, ChevronRight, Zap } from 'lucide-react';
import { Button } from '../ui/Button';
import { GlassCard } from '../ui/GlassCard';
import { ProgressBar } from '../ui/ProgressBar';
import { Step1Details } from './Step1Details';
import { Step2Style } from './Step2Style';
import { Step3Outputs } from './Step3Outputs';
import { Step4Review } from './Step4Review';
import { FormData } from '../../types';

interface WizardProps {
  step: number;
  formData: FormData;
  setFormData: (data: FormData) => void;
  onNext: () => void;
  onBack: () => void;
}

export const Wizard: React.FC<WizardProps> = ({ step, formData, setFormData, onNext, onBack }) => {
  const isStepValid = () => {
    if (step === 1) return formData.trackName && formData.artistName && formData.genre && formData.mood;
    if (step === 2) return formData.style;
    return true;
  };

  return (
    <div className="w-full max-w-5xl mx-auto p-4 md:p-6 flex flex-col flex-1 animate-fade-in">
      <ProgressBar step={step} totalSteps={4} />

      <GlassCard className="flex-1 flex flex-col p-6 md:p-10 min-h-[500px]">

        <div className="flex-1 mb-8">
          {step === 1 && <Step1Details formData={formData} setFormData={setFormData} />}
          {step === 2 && <Step2Style formData={formData} setFormData={setFormData} />}
          {step === 3 && <Step3Outputs formData={formData} setFormData={setFormData} />}
          {step === 4 && <Step4Review formData={formData} />}
        </div>

        <div className="flex items-center justify-between pt-6 border-t border-white/10">
          <Button variant="ghost" onClick={onBack} disabled={step === 1}>
            <ChevronLeft size={18} /> Back
          </Button>

          <Button onClick={onNext} disabled={!isStepValid()}>
            {step === 4 ? (
              <>Generate Pack <Zap size={18} fill="currentColor" /></>
            ) : (
              <>Next Step <ChevronRight size={18} /></>
            )}
          </Button>
        </div>

      </GlassCard>
    </div>
  );
};

import React, { useState } from 'react';
import { X } from 'lucide-react';
import { Button } from './components/ui/Button';
import { GlassCard } from './components/ui/GlassCard';
import { HeroSection } from './components/views/HeroSection';
import { Wizard } from './components/wizard/Wizard';
import { LoadingScreen } from './components/views/LoadingScreen';
import { ResultsView } from './components/views/ResultsView';
import { AbstractLoop } from './components/visuals/AbstractLoop';
import { LOADING_MESSAGES } from './constants';
import { ViewState, FormData } from './types';

export default function App() {
  const [view, setView] = useState<ViewState>('hero');
  const [showDemo, setShowDemo] = useState(false);

  // Wizard State
  const [step, setStep] = useState(1);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [loadingText, setLoadingText] = useState(LOADING_MESSAGES[0]);

  // Form Data
  const [formData, setFormData] = useState<FormData>({
    trackFile: null,
    trackName: '',
    artistName: '',
    genre: '',
    mood: '',
    style: null,
    outputs: {
      coverArt: true,
      spotifyCanvas: true,
      socialClips: true
    }
  });

  const handleStart = () => setView('wizard');

  const handleNext = () => {
    if (step < 4) setStep(step + 1);
    else handleGenerate();
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
    else setView('hero');
  };

  const handleGenerate = () => {
    setIsGenerating(true);
    let progress = 0;

    const interval = setInterval(() => {
      progress += Math.floor(Math.random() * 5) + 2;
      if (progress > 100) progress = 100;

      setLoadingProgress(progress);

      // Update loading text periodically
      if (progress % 20 === 0 && progress < 100) {
        setLoadingText(LOADING_MESSAGES[Math.floor(Math.random() * LOADING_MESSAGES.length)]);
      }

      if (progress === 100) {
        clearInterval(interval);
        setTimeout(() => {
          setIsGenerating(false);
          setView('results');
        }, 800);
      }
    }, 150);
  };

  const resetApp = () => {
    setStep(1);
    setLoadingProgress(0);
    setFormData({
      trackFile: null,
      trackName: '',
      artistName: '',
      genre: '',
      mood: '',
      style: null,
      outputs: { coverArt: true, spotifyCanvas: true, socialClips: true }
    });
    setView('wizard');
  };

  // Background Styles
  const bgStyle = {
    background: `
      radial-gradient(circle at 15% 50%, rgba(76, 29, 149, 0.4), transparent 25%),
      radial-gradient(circle at 85% 30%, rgba(219, 39, 119, 0.2), transparent 25%),
      linear-gradient(to bottom right, #0f172a, #1e1b4b, #312e81)
    `
  };

  return (
