import { GoogleGenAI, Type } from "@google/genai";
import { FormData, VisualStyle } from "../types";
import { VISUAL_STYLES } from "../constants";

// Helper to get the AI client. We create a new instance each time to ensure
// we capture the latest API key from the environment/window context.
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCreativePrompts = async (formData: FormData) => {
  const ai = getAiClient();
  const selectedStyle = VISUAL_STYLES.find(s => s.id === formData.style) || VISUAL_STYLES[0];

  const prompt = `
    Act as a creative director for a music release. 
    I need you to write visual generation prompts for an AI image generator and an AI video generator.

    Context:
    - Track Name: "${formData.trackName}"
    - Artist: "${formData.artistName}"
    - Genre: "${formData.genre}"
    - Mood: "${formData.mood}"
    - Visual Aesthetic: "${selectedStyle.title}" - ${selectedStyle.desc}

    Task:
    1. Create an 'imagePrompt' for square album cover art. It should be abstract, high-quality, and visually striking, strictly adhering to the Visual Aesthetic.
    2. Create a 'videoPrompt' for a vertical (9:16) looping background video (Spotify Canvas). It should describe movement, motion, and atmosphere compatible with the mood.

    Return the result as a JSON object.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          imagePrompt: { type: Type.STRING },
          videoPrompt: { type: Type.STRING },
        },
        required: ["imagePrompt", "videoPrompt"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    console.error("Failed to parse prompt JSON", e);
    return { imagePrompt: "", videoPrompt: "" };
  }
};

export const generateCoverArt = async (prompt: string) => {
  if (!prompt) return null;
  const ai = getAiClient();

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  // Extract the base64 image data
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const generateSpotifyCanvas = async (prompt: string) => {
  if (!prompt) return null;
  const ai = getAiClient();

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16'
    }
  });

  // Poll for completion
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000)); // Poll every 5 seconds
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;

  if (downloadLink) {
    // Fetch the video bytes using the API key
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  }

  return null;
};

