import React, { useState } from 'react';
import { X } from 'lucide-react';
import { Button } from './components/ui/Button';
import { GlassCard } from './components/ui/GlassCard';
import { HeroSection } from './components/views/HeroSection';
import { Wizard } from './components/wizard/Wizard';
import { LoadingScreen } from './components/views/LoadingScreen';
import { ResultsView } from './components/views/ResultsView';
import { AbstractLoop } from './components/visuals/AbstractLoop';
import { DemoWalkthrough } from './components/demo/DemoWalkthrough';
import { LOADING_MESSAGES } from './constants';
import { ViewState, FormData, GeneratedAssets } from './types';
import { generateCoverArt, generateCreativePrompts, generateSpotifyCanvas } from './utils/gemini';

export default function App() {
  const [view, setView] = useState<ViewState>('hero');
  const [showDemo, setShowDemo] = useState(false);

  // Wizard State
  const [step, setStep] = useState(1);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [loadingText, setLoadingText] = useState(LOADING_MESSAGES[0]);

  // Form Data
  const [formData, setFormData] = useState<FormData>({
    trackFile: null,
    audioBase64: null,
    trackName: '',
    artistName: '',
    genre: '',
    mood: '',
    style: null,
    outputs: {
      coverArt: true,
      spotifyCanvas: true,
      socialClips: true
    }
  });

  // Results State
  const [generatedAssets, setGeneratedAssets] = useState<GeneratedAssets>({});

  const handleStart = () => setView('wizard');

  const handleNext = () => {
    if (step < 4) setStep(step + 1);
    else handleGenerate();
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
    else setView('hero');
  };

  const ensureApiKey = async () => {
    try {
      if (window.aistudio && window.aistudio.hasSelectedApiKey) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          await window.aistudio.openSelectKey();
        }
        return true;
      }
    } catch (e) {
      console.error("Error checking API key", e);
    }
    return true; // Fallback or assume success if window.aistudio is missing in dev
  };

  const handleGenerate = async () => {
    await ensureApiKey();
    setIsGenerating(true);
    setLoadingProgress(5);
    setLoadingText("Initializing AI Creative Director...");

    try {
      // 1. Generate Prompts
      setLoadingText("Analyzing track & style...");
      const prompts = await generateCreativePrompts(formData);
      setLoadingProgress(25);

      const assets: GeneratedAssets = { prompts };

      // 2. Generate Cover Art
      if (formData.outputs.coverArt) {
        setLoadingText("Painting cover art pixels...");
        const coverArtUrl = await generateCoverArt(prompts.imagePrompt);
        if (coverArtUrl) assets.coverArtUrl = coverArtUrl;
        setLoadingProgress(50);
      }

      // 3. Generate Video (Spotify Canvas)
      // Note: Video generation takes longer, so we allocate more progress bar time
      if (formData.outputs.spotifyCanvas || formData.outputs.socialClips) {
        setLoadingText("Rendering video loop (this takes a moment)...");
        // We use the same video for social clips in this demo to save quota/time
        const videoUrl = await generateSpotifyCanvas(prompts.videoPrompt);
        if (videoUrl) assets.spotifyCanvasUrl = videoUrl;
        setLoadingProgress(90);
      }

      setGeneratedAssets(assets);
      setLoadingProgress(100);
      setLoadingText("Finalizing assets...");

      setTimeout(() => {
        setIsGenerating(false);
        setView('results');
      }, 500);

    } catch (error) {
      console.error("Generation failed:", error);
      setLoadingText("Error encountered. Please try again.");
      setTimeout(() => setIsGenerating(false), 2000);
    }
  };

  const resetApp = () => {
    setStep(1);
    setLoadingProgress(0);
    setGeneratedAssets({});
    setFormData({
      trackFile: null,
      audioBase64: null,
      trackName: '',
      artistName: '',
      genre: '',
      mood: '',
      style: null,
      outputs: { coverArt: true, spotifyCanvas: true, socialClips: true }
    });
    setView('wizard');
  };

  // Background Styles
  const bgStyle = {
    background: `
      radial-gradient(circle at 15% 50%, rgba(76, 29, 149, 0.4), transparent 25%),
      radial-gradient(circle at 85% 30%, rgba(219, 39, 119, 0.2), transparent 25%),
      linear-gradient(to bottom right, #0f172a, #1e1b4b, #312e81)
    `
  };

  return (
    <div className="min-h-screen text-white font-sans selection:bg-cyan-500/30 selection:text-cyan-100 overflow-x-hidden" style={bgStyle}>
      {/* Noise Texture Overlay */}
      <div className="fixed inset-0 opacity-[0.03] pointer-events-none z-0" style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}></div>

      {/* Main Content */}
      <div className="relative z-10 w-full min-h-screen flex flex-col">

        {/* Navigation / Header */}
        <nav className="w-full p-6 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('hero')}>
            <span className="font-bold text-lg tracking-tight">RVP: Release Visual Packs</span>
          </div>
          {view === 'results' && (
            <Button variant="secondary" className="!py-2 !px-4 text-sm" onClick={resetApp}>
              New Release
            </Button>
          )}
        </nav>

        {/* View Switcher */}
        <main className="flex-1 flex flex-col">
          {view === 'hero' && <HeroSection onStart={handleStart} onShowDemo={() => setShowDemo(true)} />}

          {view === 'wizard' && !isGenerating && (
            <Wizard 
              step={step} 
              formData={formData} 
              setFormData={setFormData} 
              onNext={handleNext} 
              onBack={handleBack} 
            />
          )}

          {isGenerating && (
            <div className="flex-1 flex items-center justify-center p-6 animate-fade-in">
              <LoadingScreen progress={loadingProgress} text={loadingText} />
            </div>
          )}

          {view === 'results' && (
            <ResultsView formData={formData} generatedAssets={generatedAssets} onReset={resetApp} />
          )}
        </main>

        {/* Footer */}
        <footer className="w-full p-6 text-center text-white/30 text-xs">
          <p>© 2025 RVP a NagaxMusic App | NagaVision LTD</p>
        </footer>
      </div>

      {/* Demo Modal / Live Walkthrough */}
      {showDemo && <DemoWalkthrough onClose={() => setShowDemo(false)} />}
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { FormData, VisualStyle } from "../types";
import { VISUAL_STYLES } from "../constants";

// Helper to get the AI client.
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCreativePrompts = async (formData: FormData) => {
  const ai = getAiClient();
  const selectedStyle = VISUAL_STYLES.find(s => s.id === formData.style) || VISUAL_STYLES[0];

  // Prepare content parts. If we have audio, we include it.
  const contentParts: any[] = [];

  if (formData.audioBase64) {
    contentParts.push({
      inlineData: {
        mimeType: formData.trackFile?.type || "audio/mp3",
        data: formData.audioBase64
      }
    });
    contentParts.push({ text: "Listen to this audio track carefully." });
  }

  contentParts.push({
    text: `
    Act as a world-class creative director for a music label.
    Your goal is to generate visual generation prompts that capture the *exact* essence of the provided song.

    METADATA (MANDATORY USE):
    - Track Title: "${formData.trackName}"
    - Artist Name: "${formData.artistName}"
    - Genre: "${formData.genre}"
    - Mood: "${formData.mood}"
    - Visual Aesthetic Style: "${selectedStyle.title}" (${selectedStyle.desc})

    INSTRUCTIONS:
    1. If an audio file was provided above, analyze its rhythm, energy, instrumentation, and emotional arc. Use this analysis to inform the visual movement.
    2. Design an 'imagePrompt' for the Album Cover. It MUST incorporate the vibe of the Artist "${formData.artistName}" and the title "${formData.trackName}" abstractly or thematically. It must strictly adhere to the "${selectedStyle.title}" aesthetic. High fidelity, 4k, trending on artstation.
    3. Design a 'videoPrompt' for a Spotify Canvas (9:16 vertical video). This prompt will be used by a video generation AI. It should describe a looping scene with movement that matches the audio's tempo (analyzed from file).
    4. Provide a short 'audioAnalysis' summary of what you heard (or inferred from genre/mood if audio failed).

    Output JSON format.
    `
  });

  const response = await ai.models.generateContent({
    model: 'gemini-2.0-flash', // Switched to stable Flash model which supports audio
    contents: {
      parts: contentParts
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          imagePrompt: { type: Type.STRING },
          videoPrompt: { type: Type.STRING },
          audioAnalysis: { type: Type.STRING, description: "A brief description of the music's sonic characteristics." }
        },
        required: ["imagePrompt", "videoPrompt", "audioAnalysis"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    console.error("Failed to parse prompt JSON", e);
    // Fallback if JSON fails, though schema usually prevents this
    return { 
      imagePrompt: `${selectedStyle.desc} style cover art for ${formData.trackName} by ${formData.artistName}, ${formData.mood} atmosphere`, 
      videoPrompt: `Looping abstract ${selectedStyle.title} background, ${formData.mood} motion`,
      audioAnalysis: "Analysis unavailable."
    };
  }
};

export const generateCoverArt = async (prompt: string) => {
  if (!prompt) return null;
  const ai = getAiClient();

  // We use the image model for the final render
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const generateSpotifyCanvas = async (prompt: string) => {
  if (!prompt) return null;
  const ai = getAiClient();

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;

  if (downloadLink) {
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  }

  return null;
};

