import { GoogleGenAI, Type } from "@google/genai";
import { FormData, AudioFeatures } from "../types";
import { VISUAL_STYLES, FONT_STYLES, GENRES, MOODS } from "../constants";

// Helper to get the AI client.
const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeAudioFeatures = async (audioBase64: string): Promise<AudioFeatures> => {
  const ai = getAiClient();

  // Prepare lists for the prompt
  const genreList = GENRES.join(", ");
  const moodList = MOODS.map(m => m.label).join(", ");
  const styleList = VISUAL_STYLES.map(s => `"${s.id}" (${s.desc})`).join(", ");
  const fontList = FONT_STYLES.map(f => `"${f.id}" (${f.desc})`).join(", ");

  const response = await ai.models.generateContent({
    model: 'gemini-2.0-flash',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/mp3", // Assuming MP3/WAV, API is flexible
            data: audioBase64
          }
        },
        {
          text: `Analyze this audio track. 
          Return a JSON object with:
          - bpm (estimated beats per minute as a string, e.g. "120 BPM")
          - key (musical key, e.g. "C Minor")
          - energy (Low, Medium, High)
          - valence (Sad, Neutral, Happy, Euphoric)
          - description (A very short 10-word summary of the sonic texture)

          CREATIVE SUGGESTIONS (Pick the single best fit from the provided lists):
          - suggestedGenre: Pick from [${genreList}]
          - suggestedMood: Pick from [${moodList}]
          - suggestedStyle: Pick the ID from [${styleList}]
          - suggestedFont: Pick the ID from [${fontList}]`
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          bpm: { type: Type.STRING },
          key: { type: Type.STRING },
          energy: { type: Type.STRING },
          valence: { type: Type.STRING },
          description: { type: Type.STRING },
          suggestedGenre: { type: Type.STRING },
          suggestedMood: { type: Type.STRING },
          suggestedStyle: { type: Type.STRING },
          suggestedFont: { type: Type.STRING }
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    console.error("Failed to parse audio features", e);
    return {};
  }
};

export const generateCreativePrompts = async (formData: FormData) => {
  const ai = getAiClient();
  const selectedStyle = VISUAL_STYLES.find(s => s.id === formData.style) || VISUAL_STYLES[0];
  const selectedFont = FONT_STYLES.find(f => f.id === formData.fontStyle) || FONT_STYLES[0];

  // Prepare content parts.
  const contentParts: any[] = [];

  if (formData.audioBase64) {
    contentParts.push({
      inlineData: {
        mimeType: formData.trackFile?.type || "audio/mp3",
        data: formData.audioBase64
      }
    });
  }

  // Construct a rich prompt using all available data
  let metadataText = `
    METADATA (MANDATORY USE):
    - Track Title: "${formData.trackName}"
    - Artist Name: "${formData.artistName}"
    - Genre: "${formData.genre}"
    - Mood: "${formData.mood}"
    - Visual Aesthetic Style: "${selectedStyle.title}" (${selectedStyle.desc})
    - Typography Style: "${selectedFont.name}" (${selectedFont.desc})
  `;

  if (formData.audioFeatures) {
    metadataText += `
    AUDIO ANALYSIS FEATURES:
    - BPM: ${formData.audioFeatures.bpm}
    - Key: ${formData.audioFeatures.key}
    - Energy: ${formData.audioFeatures.energy}
    - Sonic Texture: ${formData.audioFeatures.description}
    `;
  }

  contentParts.push({
    text: `
    Act as a world-class creative director for a music label.
    Your goal is to generate visual generation prompts that capture the *exact* essence of the provided song metadata and audio features.

    ${metadataText}

    INSTRUCTIONS:
    1. Analyze the provided audio (if available) and the Audio Analysis Features above.
    2. Design an 'imagePrompt' for the Album Cover. 
       - It MUST incorporate the vibe of the Artist "${formData.artistName}" and the title "${formData.trackName}".
       - It must strictly adhere to the "${selectedStyle.title}" aesthetic.
       - IMPORTANT: The typography/text style on the cover (if any text is visualized) should feel "${selectedFont.name}".
       - High fidelity, 4k, trending on artstation.
    3. Design a 'videoPrompt' for a Spotify Canvas (9:16 vertical video). 
       - This prompt will be used by a video generation AI (Veo/Imagen). 
       - It should describe a looping scene with movement that matches the audio's tempo (${formData.audioFeatures?.bpm || 'unknown BPM'}).
       - Sync the visual energy to the audio energy (${formData.audioFeatures?.energy || 'medium'}).
    4. Provide a short 'audioAnalysis' summary. If Audio Analysis Features were provided, refine them into a cohesive narrative.

    Output JSON format.
    `
  });

  const response = await ai.models.generateContent({
    model: 'gemini-2.0-flash', 
    contents: {
      parts: contentParts
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          imagePrompt: { type: Type.STRING },
          videoPrompt: { type: Type.STRING },
          audioAnalysis: { type: Type.STRING, description: "A brief description of the music's sonic characteristics and how they translate to visuals." }
        },
        required: ["imagePrompt", "videoPrompt", "audioAnalysis"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    console.error("Failed to parse prompt JSON", e);
    return { 
      imagePrompt: `${selectedStyle.desc} style cover art for ${formData.trackName}, ${selectedFont.name} typography`, 
      videoPrompt: `Looping abstract ${selectedStyle.title} background`,
      audioAnalysis: "Analysis unavailable."
    };
  }
};

export const generateCoverArt = async (prompt: string) => {
  if (!prompt) return null;
  const ai = getAiClient();

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const generateSpotifyCanvas = async (prompt: string) => {
  if (!prompt) return null;
  const ai = getAiClient();

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;

  if (downloadLink) {
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  }

  return null;
};

import React from 'react';
import { ChevronLeft, ChevronRight, Zap } from 'lucide-react';
import { Button } from '../ui/Button';
import { GlassCard } from '../ui/GlassCard';
import { ProgressBar } from '../ui/ProgressBar';
import { Step1Details } from './Step1Details';
import { Step2Style } from './Step2Style';
import { Step3Outputs } from './Step3Outputs';
import { Step4Review } from './Step4Review';
import { FormData } from '../../types';

interface WizardProps {
  step: number;
  formData: FormData;
  setFormData: (data: FormData) => void;
  onNext: () => void;
  onBack: () => void;
  onAutoGenerate: () => void;
}

export const Wizard: React.FC<WizardProps> = ({ step, formData, setFormData, onNext, onBack, onAutoGenerate }) => {
  const isStepValid = () => {
    if (step === 1) return formData.trackName && formData.artistName && formData.genre && formData.mood;
    if (step === 2) return formData.style;
    return true;
  };

  return (
    <div className="w-full max-w-5xl mx-auto p-4 md:p-6 flex flex-col flex-1 animate-fade-in">
      <ProgressBar step={step} totalSteps={4} />

      <GlassCard className="flex-1 flex flex-col p-6 md:p-10 min-h-[500px]">

        <div className="flex-1 mb-8">
          {step === 1 && (
             <Step1Details 
                formData={formData} 
                setFormData={setFormData} 
                onAutoGenerate={onAutoGenerate}
             />
          )}
          {step === 2 && <Step2Style formData={formData} setFormData={setFormData} />}
          {step === 3 && <Step3Outputs formData={formData} setFormData={setFormData} />}
          {step === 4 && <Step4Review formData={formData} />}
        </div>

        <div className="flex items-center justify-between pt-6 border-t border-white/10">
          <Button variant="ghost" onClick={onBack} disabled={step === 1}>
            <ChevronLeft size={18} /> Back
          </Button>

          <Button onClick={onNext} disabled={!isStepValid()}>
            {step === 4 ? (
              <>Generate Pack <Zap size={18} fill="currentColor" /></>
            ) : (
              <>Next Step <ChevronRight size={18} /></>
            )}
          </Button>
        </div>

      </GlassCard>
    </div>
  );
};

import React, { useState } from 'react';
import { Music, Upload, AlertCircle, Loader2, Check, Sparkles, Wand2 } from 'lucide-react';
